"""Sync `Run` handle. Pulled out of `_client.py` so the per-class
modules stay roughly the same size as the public surface they expose.

`Run` only references `Client` through its `self.client` attribute, so
the dependency is one-way: `_run` imports `_run_base` (and types); it
does not import `_client`. `_client` keeps the inverse direction
(constructing `Run` from `Client.get_run` / `list_runs`) lazy so there
is no module-load cycle.
"""

from __future__ import annotations

import json
from collections.abc import Iterator
from typing import TYPE_CHECKING, Mapping

from ._run_base import _RunBase, _TERMINAL_RUN_STATUSES
from .errors import UnsupportedRunOperationError
from .types import (
    ConversationTurn,
    RunResult,
    RunSnapshot,
    RunStreamEvent,
    SDKMessage,
    SendOptions,
)

if TYPE_CHECKING:
    from ._client import Client


class Run(_RunBase):
    """Sync handle for an in-flight or completed run.

    Inherits state, identity tracking, listener registry, and the pure
    state-mutation logic from `_RunBase`. Only sync-specific I/O
    (stream iteration, `wait`, `cancel`, `observe`, `conversation`)
    lives here.
    """

    client: "Client"

    def __init__(
        self,
        *,
        client: "Client",
        run_id: str = "",
        agent_id: str = "",
        snapshot: RunSnapshot | None = None,
        event_stream: Iterator[RunStreamEvent] | None = None,
        send_options: SendOptions | None = None,
    ) -> None:
        super().__init__(
            client=client,
            run_id=run_id,
            agent_id=agent_id,
            snapshot=snapshot,
            send_options=send_options,
        )
        self._event_stream = event_stream
        if event_stream is not None:
            self._prime_stream()

    def __iter__(self) -> Iterator[RunStreamEvent]:
        return self._events()

    def events(self) -> Iterator[RunStreamEvent]:
        return self._events()

    def stream(self) -> Iterator[SDKMessage]:
        for event in self._events():
            if event.sdk_message is not None:
                yield event.sdk_message

    def messages(self) -> Iterator[SDKMessage]:
        return self.stream()

    def iter_text(self) -> Iterator[str]:
        for message in self.stream():
            if getattr(message, "type", "") != "assistant":
                continue
            content = getattr(getattr(message, "message", None), "content", ())
            for block in content:
                text = getattr(block, "text", "")
                if text:
                    yield text

    def text(self) -> str:
        """Return the run's terminal text, blocking on `wait()` if needed.

        Defined as a method (not a property) so the blocking RPC behavior is
        explicit at the call site and the sync surface mirrors the async
        `await run.text()` shape.
        """
        if self.result:
            return self.result
        if self._terminal_result is None:
            self.wait()
        return self.result

    def wait(self) -> RunResult:
        if self._event_stream is not None or self._buffer:
            for _ in self._events():
                pass
            if self._terminal_result is not None:
                return self._result_with_accumulated_usage(self._terminal_result)
        if self._terminal_result is not None:
            return self._result_with_accumulated_usage(self._terminal_result)
        result = self.client.wait_live_run(self.id)
        # `_apply_result` now returns status-listener thunks (so the async
        # mirror can await them); invoke them directly here.
        for callback in self._apply_result(result):
            callback()
        self._terminal_result = result
        return self._result_with_accumulated_usage(result)

    def observe(self, *, after_offset: str | None = None) -> Iterator[RunStreamEvent]:
        return self.client.observe_run(self.id, after_offset=after_offset)

    def cancel(self) -> None:
        if self.status in _TERMINAL_RUN_STATUSES:
            raise UnsupportedRunOperationError(
                "cancel",
                f"Run {self.id!r} is already in terminal status {self.status!r}; "
                "cancel is not applicable.",
            )
        self.client.cancel_run(self.id, agent_id=self.agent_id)

    def conversation_json(self) -> str:
        response = self.client._agent_unary("GetRunConversation", {"runId": self.id})
        return str(response.get("conversationJson", ""))

    def conversation(self) -> list[ConversationTurn]:
        raw = self.conversation_json()
        if not raw:
            return []
        loaded = json.loads(raw)
        if not isinstance(loaded, list):
            return []
        return [
            ConversationTurn.from_json(item)
            for item in loaded
            if isinstance(item, Mapping)
        ]

    def _prime_stream(self) -> None:
        if self._event_stream is None:
            return
        try:
            event = next(self._event_stream)
        except StopIteration:
            self._event_stream = None
            return
        self._handle_event(event)
        self._buffer.append(event)

    def _events(self) -> Iterator[RunStreamEvent]:
        while self._buffer:
            yield self._buffer.pop(0)
        while self._event_stream is not None:
            try:
                event = next(self._event_stream)
            except StopIteration:
                self._event_stream = None
                return
            self._handle_event(event)
            yield event

    def _handle_event(self, event: RunStreamEvent) -> None:
        # State-only side-effects happen inside `_apply_event_state`
        # (shared with AsyncRun via `_RunBase`). The only sync-specific
        # work here is invoking returned thunks directly; AsyncRun
        # awaits any awaitable they return.
        for callback in self._apply_event_state(event):
            callback()
